#!/usr/bin/env python3
# Vendor Suit -- Phase 6-C(ii): invoice WRITES through Harvey/Donna.
# create -> donna_client + donna_money(in) + witnessed advance split
# payment -> read-before-write -> donna_money_edit (absolutes)
# cancel  -> donna_hide      update -> donna_edit / donna_money_edit
# :id is a binder id; ownership enforced by executeRecordTool agent-scope.
# Guarded + idempotent.  unzip -o vendor-suit-phase6cii-invoices-write-v1.zip && python3 writer.py
import os, sys, base64, json
ROOT = os.getcwd()
def die(m): print("ABORT: " + m); sys.exit(1)
if not os.path.isfile("package.json") or json.load(open("package.json")).get("name") != "dream-os-backend":
    die("run from the dream-os repo root.")
if not os.path.isfile(os.path.join(ROOT,"src","engine","tsconfig.json")):
    die("src/engine missing -- run Phase 0 first.")
F = os.path.join(ROOT, "src", "api", "vendor", "invoices.js")
P = {'helpers': '', 'old_create': '', 'new_create': '', 'old_payments': '', 'new_payments': '', 'old_cancel': '', 'new_cancel': '', 'old_update': '', 'new_update': ''}
dec = lambda k: base64.b64decode(P[k]).decode()
txt = open(F, encoding="utf-8").read()

if "6-C(ii) — create through Donna" in txt:
    print("= invoice writes already flipped (idempotent)."); sys.exit(0)
if "6-C(i) — invoices read Harvey/Donna" not in txt and "deriveInvoiceState" not in txt:
    die("6-C(i) not applied -- apply the invoice read-flip first (deriveInvoiceState needed).")

# 1 — helpers + executeRecordTool require, after the existing require block
anchor = "const { generateInvoicePdf }  = require('../../lib/invoicePdf');"
if anchor not in txt: die("require anchor not found -- inspect.")
txt = txt.replace(anchor, anchor + "\n" + dec("helpers"), 1)
print("+ added executeRecordTool + binderToInvoiceShape/readBinderAsInvoice helpers")

# 2 — swap the four handlers
for name in ["create","payments","cancel","update"]:
    old, new = dec("old_"+name), dec("new_"+name)
    if old not in txt: die(f"{name} handler not found verbatim -- inspect.")
    txt = txt.replace(old, new, 1); print(f"+ {name} -> Donna primitives")

open(F,"w",encoding="utf-8").write(txt)
print("\nDone. npm run build:engine, restart.")
